import org.junit.Test;
import jetbrains.mps.lang.dataFlow.framework.Program;
import jetbrains.mps.lang.dataFlow.framework.SimpleProgramBuilder;
import jetbrains.mps.lang.dataFlow.framework.AnalysisResult;
import jetbrains.mps.lang.dataFlow.framework.VarSet;
import jetbrains.mps.lang.dataFlow.framework.analyzers.LivenessAnalyzer;
import org.junit.Assert;

public class LivenessAnalysisTest {
  @Test
  public void linearProgram() {
    Program p = new SimpleProgramBuilder().emitRead("x").emitWrite("y").emitRead("z").buildProgram();
    AnalysisResult<VarSet> analysisResult = p.analyze(new LivenessAnalyzer());
    Assert.assertEquals("0: read x [x, z]\n1: write y [z]\n2: read z [z]\n3: end []\n", analysisResult.toString());
  }
  @Test
  public void overwrite() {
    Program p = new SimpleProgramBuilder().emitRead("x").emitWrite("x").buildProgram();
    AnalysisResult<VarSet> analysisResult = p.analyze(new LivenessAnalyzer());
    Assert.assertEquals("0: read x [x]\n1: write x []\n2: end []\n", analysisResult.toString());
  }
  @Test
  public void cyclicProgram() {
    Program p = new SimpleProgramBuilder().emitRead("y").emitRead("x").emitIfJump(0).buildProgram();
    AnalysisResult<VarSet> analysisResult = p.analyze(new LivenessAnalyzer());
    Assert.assertEquals("0: read y [x, y]\n1: read x [x, y]\n2: ifjump 0 [x, y]\n3: end []\n", analysisResult.toString());
  }
}
